// Get AI Agent output string
const aiOutput = $input.first().json.output;

// Parse JSON safely
let parsed;

try {
  parsed = JSON.parse(aiOutput);
} catch (error) {
  throw new Error("AI output is not valid JSON: " + aiOutput);
}

// Return structured data
return [
  {
    json: {
      intent: parsed.intent,
      confidence: parsed.confidence,
      context_sufficient: parsed.context_sufficient,
      follow_up_question: parsed.follow_up_question
    }
  }
];

// Get all input items
const items = $input.all();

// Filter out empty items (no keys or null data)
const nonEmptyItems = items.filter(item => {
  const data = item.json;
  return data && Object.keys(data).length > 0;
});

let resultData = { result: false };

// If there’s any non-empty item, take the first one’s data
if (nonEmptyItems.length > 0) {
  resultData = {
    ...nonEmptyItems[0].json, // keep the actual data
    result: true
  };
}

// Return a single output object
return [{ json: resultData }];

// Get raw output from previous node
const raw = $input.first().json.output || $input.first().json.message?.content;

// Parse safely
let parsed;

try {
  parsed = typeof raw === "string"
    ? JSON.parse(raw.replace(/```(?:json)?/g, '').trim())
    : raw;
} catch (e) {
  return [{ json: { result: "ema" } }];
}

// If email exists → return only email
if (parsed.email_provided && parsed.email_address) {
  return [{
    json: {
      result: parsed.email_address
    }
  }];
}

// If not provided → return ""
return [{
  json: {
    result: ""
  }
}];

